import type { ExamQuestion } from "./types";

export const nephrologyQuestions: ExamQuestion[] = [
  { q: "A patient's labs show BUN 45 mg/dL, creatinine 4.2 mg/dL, potassium 6.1 mEq/L, and urine output of 100 mL in 12 hours. Which condition does the nurse suspect?", o: ["Chronic kidney disease", "Acute kidney injury with oliguria", "Nephrotic syndrome", "Urinary tract infection"], a: 1, r: "Elevated BUN and creatinine with oliguria (urine output <400 mL/day or <0.5 mL/kg/hr) and hyperkalemia indicate acute kidney injury. The sudden elevation in wastes and electrolyte imbalance reflect acute loss of renal function. CKD develops gradually over months to years.", s: "Acute Kidney Injury" },
  { q: "A patient with AKI has a fractional excretion of sodium (FENa) of 0.5%. This finding is most consistent with:", o: ["Intrinsic renal failure", "Prerenal azotemia - the kidneys are appropriately retaining sodium", "Postrenal obstruction", "Chronic kidney disease"], a: 1, r: "FENa <1% indicates prerenal azotemia where the kidneys are functioning normally and appropriately retaining sodium in response to decreased perfusion (dehydration, heart failure, hemorrhage). FENa >2% suggests intrinsic renal damage where tubules have lost the ability to concentrate urine and reabsorb sodium.", s: "Acute Kidney Injury" },
  { q: "A patient with CKD Stage 3 has a GFR of 42 mL/min. The nurse expects the care plan to focus on:", o: ["Preparation for immediate dialysis", "Slowing disease progression through BP control, diabetes management, and nephrotoxic drug avoidance", "No interventions needed at this stage", "Kidney transplant evaluation"], a: 1, r: "CKD Stage 3 (GFR 30-59 mL/min) is a critical window for slowing progression. Key interventions include blood pressure control (target <130/80 with ACE/ARB), diabetes management (HbA1c <7%), avoiding nephrotoxic medications (NSAIDs, contrast dye), dietary modifications, and treating complications (anemia, metabolic acidosis, mineral bone disease). Dialysis is not typically needed until Stage 5 (GFR <15).", s: "Chronic Kidney Disease" },
  { q: "A patient on hemodialysis has an AV fistula in the left arm. Which nursing action is CONTRAINDICATED?", o: ["Assessing for a thrill and bruit daily", "Taking blood pressure or drawing blood from the fistula arm", "Elevating the arm post-operatively", "Teaching the patient to avoid tight clothing on the access arm"], a: 1, r: "Blood pressure measurement, venipuncture, IV starts, and tourniquets are CONTRAINDICATED on the fistula arm as they can damage or occlude the fistula. The nurse should assess for thrill (palpable vibration) and bruit (audible swishing) which indicate fistula patency. Loss of thrill or bruit requires immediate notification as it may indicate clotting.", s: "Hemodialysis" },
  { q: "During hemodialysis, a patient develops sudden chest pain, dyspnea, and cyanosis. The nurse suspects air embolism. What is the priority intervention?", o: ["Continue dialysis and administer oxygen", "Clamp the blood tubing, position the patient on the left side in Trendelenburg, and call for emergency assistance", "Place the patient supine and elevate both legs", "Administer heparin to prevent clot formation"], a: 1, r: "Air embolism during dialysis is a medical emergency. Actions: immediately clamp the venous blood line to prevent more air from entering, position patient on LEFT side in Trendelenburg (traps air in the right atrium away from pulmonary vasculature), administer 100% oxygen, and call for emergency assistance. Left lateral decubitus position prevents air from entering the pulmonary outflow tract.", s: "Hemodialysis" },
  { q: "A patient on peritoneal dialysis develops cloudy dialysate effluent with abdominal pain and fever. What does the nurse suspect?", o: ["Normal dialysis findings", "Peritonitis - the most common and serious complication of peritoneal dialysis", "Bowel perforation", "Catheter malposition"], a: 1, r: "Cloudy effluent is the hallmark sign of peritonitis in peritoneal dialysis patients. The triad is: cloudy effluent, abdominal pain, and fever. Effluent should be sent for culture and cell count (WBC >100/mm³ with >50% neutrophils confirms peritonitis). Treatment includes intraperitoneal antibiotics. The most common organisms are skin flora (S. epidermidis, S. aureus) introduced during exchanges.", s: "Peritoneal Dialysis" },
  { q: "A patient with CKD Stage 5 has a potassium level of 6.8 mEq/L. The ECG shows peaked T waves. What is the priority intervention?", o: ["Administer oral kayexalate", "Administer IV calcium gluconate to stabilize the myocardium", "Restrict dietary potassium", "Schedule hemodialysis for tomorrow"], a: 1, r: "Hyperkalemia >6.5 mEq/L with ECG changes (peaked T waves, widened QRS, loss of P waves) is a medical emergency requiring immediate intervention. IV calcium gluconate stabilizes the cardiac membrane within minutes (does not lower potassium but protects the heart). Then insulin + dextrose, sodium bicarbonate, or nebulized albuterol to shift potassium intracellularly. Kayexalate and dialysis remove potassium but take longer.", s: "Electrolyte Management" },
  { q: "A nurse is educating a patient with CKD about dietary restrictions. Which statement by the patient indicates understanding?", o: ["'I should increase my protein intake to maintain muscle mass'", "'I need to limit potassium, phosphorus, sodium, and fluid intake, and eat moderate protein as prescribed'", "'I can eat as much fruit as I want'", "'Salt substitutes are a safe alternative for me'"], a: 1, r: "CKD dietary management includes: limiting potassium (avoid bananas, oranges, potatoes, tomatoes), phosphorus (avoid dairy, nuts, colas), sodium (<2g/day), and fluids (based on urine output + insensible losses). Protein is moderated (0.6-0.8 g/kg in pre-dialysis CKD) to reduce uremic waste production. Salt substitutes contain potassium chloride and are DANGEROUS in CKD patients.", s: "Renal Diet" },
  { q: "A patient with CKD has hemoglobin 8.2 g/dL and is prescribed epoetin alfa (Epogen). What is the target hemoglobin range?", o: ["12-14 g/dL", "10-11.5 g/dL - higher targets increase cardiovascular risk", "8-9 g/dL", "14-16 g/dL"], a: 1, r: "CKD-related anemia is treated with erythropoiesis-stimulating agents (ESAs) targeting hemoglobin 10-11.5 g/dL. Studies (CHOIR, CREATE, TREAT) showed that targeting higher hemoglobin levels (>13 g/dL) with ESAs increases cardiovascular events, stroke, and mortality. Iron stores (ferritin, TSAT) must be adequate before ESA therapy. Common side effects include hypertension and pure red cell aplasia.", s: "Renal Pharmacology" },
  { q: "A patient post-kidney transplant is on tacrolimus, mycophenolate, and prednisone. What is the MOST important teaching about infection prevention?", o: ["No special precautions are needed", "Avoid live vaccines, practice meticulous hand hygiene, avoid crowds during peak immunosuppression, and report any signs of infection immediately as they may be blunted by immunosuppression", "Only take immunosuppressants when feeling ill", "Antibiotic prophylaxis is sufficient protection"], a: 1, r: "Transplant recipients on immunosuppression have increased infection risk and may not mount a normal immune response (fever may be absent or blunted). Teaching includes: avoid live vaccines (MMR, varicella, oral polio, live influenza), practice hand hygiene, avoid sick contacts and crowds, food safety (no raw meats, unwashed produce), report ANY sign of infection, and never skip immunosuppressive medications (increases rejection risk).", s: "Transplant Nursing" },
  { q: "A patient with nephrotic syndrome presents with severe edema, proteinuria >3.5 g/day, hypoalbuminemia, and hyperlipidemia. Which complication should the nurse monitor for?", o: ["Hyperkalemia", "Thromboembolic events - loss of antithrombin III and other anticoagulant proteins in the urine", "Metabolic acidosis", "Hypernatremia"], a: 1, r: "Nephrotic syndrome causes massive proteinuria, leading to loss of albumin (edema), immunoglobulins (infection risk), antithrombin III and other coagulation inhibitors (hypercoagulable state with risk of renal vein thrombosis, DVT, PE), and vitamin D binding protein (bone disease). The hypercoagulable state is the most dangerous acute complication. Lipid abnormalities occur from increased hepatic lipoprotein synthesis.", s: "Glomerular Disorders" },
  { q: "A patient with a ureteral stent reports urinary frequency, urgency, and flank pain during voiding. The nurse should:", o: ["Report these as signs of pyelonephritis", "Explain that these are common expected symptoms of a ureteral stent and encourage adequate fluid intake and analgesics as prescribed", "Remove the stent immediately", "Restrict fluid intake"], a: 1, r: "Ureteral stents commonly cause lower urinary tract symptoms: frequency, urgency, dysuria, hematuria, and flank pain during voiding (urine reflux up the stent). These are expected but can be distressing. Management includes alpha-blockers (tamsulosin) to reduce stent symptoms, adequate hydration, and analgesics. Patients should report fever, inability to urinate, or worsening pain (may indicate stent migration or obstruction).", s: "Urinary Disorders" },
  { q: "A patient is admitted with rhabdomyolysis after a crush injury. Which laboratory finding is most concerning for the development of AKI?", o: ["Elevated AST", "Creatine kinase (CK) >10,000 U/L with myoglobinuria", "Elevated LDH", "Low albumin"], a: 1, r: "Rhabdomyolysis releases myoglobin from damaged muscle, which is nephrotoxic and can precipitate in renal tubules causing pigment-induced AKI. CK >5,000 U/L significantly increases AKI risk; >10,000 U/L carries very high risk. Treatment is aggressive IV fluid resuscitation (200-300 mL/hr initially) to maintain urine output >200-300 mL/hr, which dilutes myoglobin and prevents tubular precipitation. Urine appears tea/cola-colored.", s: "Acute Kidney Injury" },
  { q: "A patient with polycystic kidney disease (PKD) asks about the inheritance pattern. The nurse explains that the most common form (ADPKD) is:", o: ["X-linked recessive", "Autosomal dominant - each child of an affected parent has a 50% chance of inheriting the condition", "Autosomal recessive", "Sporadic with no genetic component"], a: 1, r: "Autosomal Dominant Polycystic Kidney Disease (ADPKD) is the most common hereditary kidney disease, affecting 1 in 400-1,000 people. Each child of an affected parent has a 50% chance of inheriting the PKD1 or PKD2 gene mutation. ADPKD typically presents in adulthood (30s-50s) with bilateral enlarging renal cysts, hypertension, pain, hematuria, and progressive CKD. Associated conditions include hepatic cysts and cerebral aneurysms.", s: "Genetic Kidney Disease" },
  { q: "A nurse is caring for a patient receiving continuous renal replacement therapy (CRRT). What is a key nursing responsibility during CRRT?", o: ["Discontinue anticoagulation during CRRT", "Monitor the filter for clotting, maintain accurate fluid balance calculations, and assess hemodynamic stability frequently", "CRRT does not require nursing monitoring", "Allow the patient to ambulate freely during treatment"], a: 1, r: "CRRT nursing responsibilities include: continuous hemodynamic monitoring (hypotension is common), strict I&O with hourly fluid balance calculations, filter/circuit monitoring for clotting (increased pressures, darkening blood), anticoagulation management (citrate or heparin), electrolyte monitoring (frequent labs), temperature monitoring (CRRT causes heat loss), and medication dose adjustments (many drugs are cleared by CRRT).", s: "CRRT" },
  { q: "A patient with CKD has a phosphorus level of 7.2 mg/dL and calcium of 8.0 mg/dL. Which medication should the nurse expect to be ordered?", o: ["Calcium supplements without meal timing consideration", "Phosphate binders (sevelamer, calcium acetate) to be taken WITH meals to bind dietary phosphorus in the GI tract", "Vitamin D supplements only", "No treatment needed for these levels"], a: 1, r: "CKD-mineral bone disease involves hyperphosphatemia (kidneys cannot excrete phosphorus), hypocalcemia (reduced vitamin D activation), and secondary hyperparathyroidism. Phosphate binders must be taken WITH meals to bind dietary phosphorus in the gut and prevent absorption. Calcium-based binders (calcium acetate) also supplement calcium. Non-calcium binders (sevelamer, lanthanum) are preferred if calcium is elevated to prevent vascular calcification.", s: "Renal Pharmacology" },
  { q: "A patient with an AV graft for hemodialysis develops redness, warmth, and purulent drainage at the graft site. The nurse should:", o: ["Apply warm compresses and continue dialysis", "Withhold dialysis from the graft site, notify the provider, obtain cultures, and assess for systemic infection signs", "Clean the site and apply a bandage", "Use the graft for dialysis and start oral antibiotics"], a: 1, r: "Signs of vascular access infection (redness, warmth, swelling, purulent drainage, fever) require immediate attention. AV graft infections are more common than AV fistula infections and can lead to sepsis, bacteremia, and endocarditis. The infected access should NOT be used for dialysis. Blood and wound cultures should be obtained before starting antibiotics. Graft infections often require surgical intervention (partial or complete graft excision).", s: "Vascular Access" },
  { q: "A patient receiving IV contrast dye for a CT scan has a creatinine of 1.8 mg/dL. What preventive measure is MOST important?", o: ["No prevention needed", "Adequate IV hydration with isotonic saline before and after the procedure to prevent contrast-induced nephropathy", "Administer mannitol before the procedure", "Give furosemide to increase urine output"], a: 1, r: "Contrast-induced nephropathy (CIN) risk increases with baseline renal impairment, diabetes, heart failure, and use of nephrotoxic drugs. Prevention includes: IV hydration with isotonic saline (1 mL/kg/hr for 6-12 hours before and after), using the lowest volume of iso-osmolar or low-osmolar contrast, holding metformin (risk of lactic acidosis if AKI develops), and discontinuing nephrotoxic medications. N-acetylcysteine has uncertain benefit.", s: "Renal Protection" },
  { q: "A patient with diabetic nephropathy has microalbuminuria (30-300 mg/day). The nurse knows the first-line medication to slow progression is:", o: ["Furosemide", "ACE inhibitor or ARB - these reduce intraglomerular pressure and proteinuria independent of blood pressure effect", "Calcium channel blocker", "Beta-blocker"], a: 1, r: "ACE inhibitors (enalapril, lisinopril) or ARBs (losartan, valsartan) are first-line for diabetic nephropathy because they reduce intraglomerular pressure by dilating the efferent arteriole, decreasing proteinuria and slowing progression to ESRD. This benefit is independent of their blood pressure-lowering effect. Monitor for hyperkalemia and rising creatinine (up to 30% increase is acceptable and expected).", s: "Diabetic Kidney Disease" },
  { q: "A patient on hemodialysis complains of severe headache, nausea, vomiting, restlessness, and altered consciousness during treatment. What does the nurse suspect?", o: ["Normal dialysis symptoms", "Dialysis disequilibrium syndrome - caused by rapid removal of urea creating an osmotic gradient between blood and brain", "Air embolism", "Myocardial infarction"], a: 1, r: "Dialysis disequilibrium syndrome occurs when urea is removed from the blood faster than from the brain, creating an osmotic gradient that draws water into brain cells (cerebral edema). Symptoms range from headache, nausea, and restlessness to seizures and coma. Prevention: slow, shorter initial dialysis sessions with lower blood flow rates in new patients. Treatment: slow or stop dialysis, administer hypertonic saline or mannitol.", s: "Hemodialysis" },
  { q: "A patient with lupus nephritis has proteinuria, hematuria, and rising creatinine. The nurse anticipates which diagnostic procedure?", o: ["CT scan of the abdomen", "Renal biopsy to determine the class of lupus nephritis and guide treatment", "Cystoscopy", "MRI of the kidneys"], a: 1, r: "Renal biopsy is essential in lupus nephritis to determine the ISN/RPS class (I-VI), which guides treatment intensity. Class III (focal) and Class IV (diffuse proliferative, most common and severe) require aggressive immunosuppression (cyclophosphamide or mycophenolate + corticosteroids). Class V (membranous) may have a different approach. Biopsy findings directly determine prognosis and treatment.", s: "Glomerular Disorders" },
  { q: "A post-kidney transplant patient develops fever, graft tenderness, decreased urine output, and rising creatinine 2 weeks after surgery. The nurse suspects:", o: ["Normal post-operative recovery", "Acute rejection - requiring immediate evaluation and treatment escalation with pulse steroids or anti-thymocyte globulin", "Urinary tract infection", "Dehydration"], a: 1, r: "Acute rejection typically occurs days to months post-transplant and presents with: graft tenderness, decreased urine output, fever, rising creatinine, hypertension, and weight gain. It is a T-cell mediated response against the foreign kidney. Treatment includes pulse methylprednisolone (mild-moderate) or anti-thymocyte globulin/OKT3 (severe). Renal biopsy confirms rejection and grades severity. Early detection and treatment are critical for graft survival.", s: "Transplant Nursing" },
  { q: "A patient with end-stage renal disease on dialysis has severe secondary hyperparathyroidism with calcium 11.2 mg/dL. What complication is the nurse most concerned about?", o: ["Osteoporosis only", "Calciphylaxis - vascular calcification causing painful, necrotic skin lesions with very high mortality", "Hypokalemia", "Metabolic alkalosis"], a: 1, r: "Calciphylaxis (calcific uremic arteriolopathy) is a severe, life-threatening complication of CKD with very high calcium-phosphorus product. Small vessel calcification causes ischemic necrosis of skin and subcutaneous tissue, presenting as extremely painful, violaceous (purplish) skin lesions that become necrotic. Mortality is 60-80%. Risk factors include: high Ca x P product, warfarin use, obesity, and diabetes. Treatment includes sodium thiosulfate, wound care, and parathyroidectomy.", s: "CKD Complications" },
  { q: "A patient on hemodialysis has completed the session. The nurse notes the access site is bleeding after needle removal. What is the appropriate action?", o: ["Apply a tourniquet proximal to the site", "Apply firm, direct pressure for 10-20 minutes without occluding the access; avoid excessive pressure that could clot the fistula", "Apply an ice pack only", "Cover with a bandage and discharge the patient"], a: 1, r: "After hemodialysis needle removal, apply firm but not occlusive pressure for 10-20 minutes. The pressure should stop bleeding without compressing the fistula/graft (which could cause clotting). After achieving hemostasis, check for continued thrill and bruit to confirm fistula patency. Patients on anticoagulation may require longer pressure. Do NOT use tourniquet as it can damage the access.", s: "Hemodialysis" },
  { q: "A patient with nephritic syndrome presents with hematuria, hypertension, oliguria, and periorbital edema. Which laboratory finding is expected?", o: ["Massive proteinuria >3.5 g/day", "Red blood cell casts in urinalysis, elevated ASO titer, and low complement levels (if post-streptococcal)", "Hyperlipidemia", "Hypokalemia"], a: 1, r: "Nephritic syndrome involves glomerular INFLAMMATION causing hematuria (RBC casts are pathognomonic of glomerulonephritis), hypertension, oliguria, and mild-moderate proteinuria (<3.5 g/day). In post-streptococcal glomerulonephritis: elevated ASO titer (confirms recent strep infection), low C3 complement (consumed by immune complexes). Compare with nephrotic syndrome: massive proteinuria, hypoalbuminemia, edema, hyperlipidemia.", s: "Glomerular Disorders" },
  { q: "A patient with chronic kidney disease is taking sodium polystyrene sulfonate (Kayexalate) for hyperkalemia. What side effect should the nurse monitor for?", o: ["Hyperkalemia rebound", "Intestinal necrosis (bowel necrosis) - a rare but serious complication, especially when given with sorbitol", "Hypertension", "Hypernatremia only"], a: 1, r: "Sodium polystyrene sulfonate exchanges sodium for potassium in the GI tract. Serious complications include intestinal necrosis (especially when combined with sorbitol, which is now avoided), constipation, sodium retention (edema and hypertension), and hypokalemia from excessive use. Newer potassium binders (patiromer, sodium zirconium cyclosilicate) have better safety profiles and are increasingly preferred.", s: "Renal Pharmacology" },
  { q: "A patient presents with severe flank pain radiating to the groin, hematuria, and nausea. CT shows a 4mm calcium oxalate stone in the distal ureter. What is the most likely management?", o: ["Immediate surgical intervention", "Conservative management with IV hydration, pain control, alpha-blocker (tamsulosin) for medical expulsive therapy, and strain all urine - most stones <5mm pass spontaneously", "Lithotripsy as first-line treatment", "Permanent ureteral stent placement"], a: 1, r: "Stones <5mm have an approximately 90% chance of spontaneous passage. Management includes: aggressive IV hydration (increases urine flow to flush the stone), pain management (NSAIDs first-line, opioids for severe pain), alpha-blockers like tamsulosin (relax ureteral smooth muscle, facilitating passage), antiemetics, and straining all urine to capture the stone for analysis. Stones >10mm or with complications typically require intervention.", s: "Urolithiasis" },
  { q: "A patient on peritoneal dialysis asks why the dwell time is important. The nurse explains:", o: ["Dwell time is not important and can be any length", "Dwell time determines how long the dialysate remains in the peritoneal cavity for solute and fluid exchange across the peritoneal membrane; too short reduces clearance, too long reduces ultrafiltration due to glucose absorption", "Longer dwell time is always better", "Dwell time only affects fluid removal"], a: 1, r: "Dwell time (the period dialysate remains in the peritoneal cavity) affects dialysis adequacy. During the dwell, uremic toxins diffuse from blood into dialysate (solute clearance) and excess fluid moves via osmosis (ultrafiltration). Short dwells provide less clearance. However, excessively long dwells allow glucose absorption from the dialysate, reducing the osmotic gradient and decreasing ultrafiltration (fluid removal). Optimal dwell times are determined by peritoneal equilibration testing (PET).", s: "Peritoneal Dialysis" },
  { q: "A patient with CKD has a PTH level of 450 pg/mL (normal 10-65). The nurse understands this indicates:", o: ["Normal parathyroid function", "Secondary hyperparathyroidism from CKD - the parathyroid glands are overproducing PTH in response to hypocalcemia and hyperphosphatemia", "Primary hyperparathyroidism", "Hypoparathyroidism"], a: 1, r: "Secondary hyperparathyroidism in CKD results from: (1) decreased renal phosphorus excretion causing hyperphosphatemia, (2) decreased renal activation of vitamin D (1,25-dihydroxyvitamin D) causing decreased calcium absorption, and (3) hypocalcemia stimulating PTH release. Chronically elevated PTH causes renal osteodystrophy (bone pain, fractures, metastatic calcification). Treatment: phosphate binders, active vitamin D (calcitriol), calcimimetics (cinacalcet), and ultimately parathyroidectomy if refractory.", s: "CKD Complications" },
  { q: "A nurse is performing peritoneal dialysis and the outflow is less than expected. What should the nurse assess first?", o: ["Increase the dwell time", "Check for kinks in the tubing, ensure the drainage bag is below the abdomen, reposition the patient (side to side, elevating HOB), and assess for constipation which can impede drainage", "Add more dialysate", "Clamp the catheter and call the physician"], a: 1, r: "Poor PD outflow troubleshooting: (1) Check tubing for kinks or clamps, (2) Lower the drainage bag below abdominal level (gravity-dependent), (3) Reposition the patient (side to side, sitting up) to move the catheter tip away from tissue, (4) Assess for constipation (stool in the sigmoid colon can obstruct the catheter), (5) Check for fibrin strands in the tubing. Persistent poor drainage may indicate catheter malposition requiring radiographic evaluation.", s: "Peritoneal Dialysis" },
  { q: "A patient is prescribed tacrolimus after kidney transplant. What level monitoring and side effects should the nurse be aware of?", o: ["No monitoring is needed", "Trough levels are monitored to maintain therapeutic range; side effects include nephrotoxicity, neurotoxicity (tremor, headache), hyperglycemia, hypertension, and hyperkalemia", "Only CBC monitoring is needed", "Tacrolimus has no significant side effects"], a: 1, r: "Tacrolimus (a calcineurin inhibitor) has a narrow therapeutic index requiring trough level monitoring. Major toxicities include: nephrotoxicity (can damage the transplanted kidney it's meant to protect), neurotoxicity (tremor, headache, seizures), new-onset diabetes (hyperglycemia), hypertension, hyperkalemia, and increased infection/malignancy risk. Drug interactions are extensive (CYP3A4 substrate). Grapefruit juice and certain medications increase levels.", s: "Transplant Pharmacology" },
  { q: "A patient with stage 4 CKD (GFR 22 mL/min) asks when they should start planning for dialysis. The nurse responds:", o: ["Dialysis planning should start when you can no longer urinate", "Planning should begin NOW: vascular access creation (AV fistula) should occur when GFR drops below 25 mL/min because the fistula needs 2-3 months to mature before use", "Dialysis planning can wait until Stage 5", "You will never need dialysis with stage 4"], a: 1, r: "AV fistula creation should ideally occur when GFR drops below 25 mL/min (6-12 months before anticipated dialysis need) because fistulas require 2-3 months (sometimes up to 6 months) to mature before they can be used. Early referral to nephrology, vascular access planning, transplant evaluation, and dialysis modality education should all occur during CKD Stage 4. Late referral leads to temporary catheter use with higher infection and complication rates.", s: "CKD Management" },
  { q: "A patient with hyponatremia (sodium 118 mEq/L) is being treated with hypertonic (3%) saline. What is the maximum safe rate of sodium correction?", o: ["Correct as fast as possible to normalize levels", "No more than 8-10 mEq/L in 24 hours to prevent osmotic demyelination syndrome (central pontine myelinolysis)", "Correct by 20 mEq/L in the first 12 hours", "There is no maximum rate"], a: 1, r: "Rapid correction of chronic hyponatremia causes osmotic demyelination syndrome (ODS, formerly central pontine myelinolysis): water shifts OUT of brain cells too rapidly, causing demyelination of pontine neurons. This results in devastating neurological damage: quadriplegia, pseudobulbar palsy, 'locked-in syndrome.' The safe rate is 8-10 mEq/L per 24 hours (some guidelines say 6-8 mEq/L). Frequent sodium monitoring (every 2-4 hours) and desmopressin can be used to slow correction if it proceeds too rapidly.", s: "Electrolyte Management" },
  { q: "A patient with ESRD receiving erythropoietin (EPO) therapy has hemoglobin that is not responding after 4 weeks. What should the nurse assess?", o: ["The EPO dose needs to be doubled immediately", "Assess for iron deficiency (check ferritin and transferrin saturation) - iron is the most common cause of EPO resistance", "Nothing can be done", "Switch to a blood transfusion only"], a: 1, r: "Iron deficiency is the most common cause of EPO hypo-responsiveness. Iron stores must be adequate for erythropoiesis: target ferritin >200 ng/mL and transferrin saturation (TSAT) >20% in dialysis patients. Other causes of EPO resistance include: chronic inflammation/infection, secondary hyperparathyroidism, aluminum toxicity, folate/B12 deficiency, and occult blood loss (GI bleeding). IV iron supplementation is preferred in dialysis patients (oral iron is poorly absorbed).", s: "Renal Pharmacology" },
  { q: "A patient presents with metabolic acidosis (pH 7.28, HCO3 14 mEq/L) in the setting of CKD. The nurse understands the cause is:", o: ["Excessive bicarbonate production", "Decreased renal excretion of hydrogen ions and decreased bicarbonate regeneration by failing kidneys", "Respiratory compensation failure", "Excessive acid intake"], a: 1, r: "In CKD, the kidneys lose the ability to excrete hydrogen ions (H+) and regenerate bicarbonate (HCO3-), leading to metabolic acidosis. This contributes to muscle wasting, bone disease, and CKD progression. Treatment includes oral sodium bicarbonate supplementation when serum bicarbonate falls below 22 mEq/L. Compensation occurs through increased respiratory rate (Kussmaul breathing) to blow off CO2. Dialysis helps correct acidosis.", s: "Acid-Base Balance" },
  { q: "A nurse is caring for a patient with hepatorenal syndrome (HRS). Which finding is characteristic?", o: ["Massive proteinuria", "Progressive renal failure in a patient with advanced liver disease (ascites, jaundice), with bland urine sediment and very low urinary sodium (<10 mEq/L)", "Hematuria with RBC casts", "Polyuria and hypernatremia"], a: 1, r: "Hepatorenal syndrome occurs in advanced liver disease (usually with portal hypertension and ascites) when splanchnic vasodilation causes compensatory renal vasoconstriction, reducing renal blood flow and GFR. Findings: rising creatinine, oliguria, very low urinary sodium (<10 mEq/L), bland urine sediment (no casts, no protein - the kidneys are structurally normal), and features of liver failure. Treatment: terlipressin or midodrine + octreotide + albumin. Definitive treatment is liver transplant.", s: "Hepatorenal Syndrome" },
  { q: "A patient is receiving hemodialysis through a tunneled central venous catheter (CVC). What is the nurse's priority concern?", o: ["Cosmetic appearance of the catheter", "Central line-associated bloodstream infection (CLABSI) - CVCs have the highest infection rate of all dialysis access types", "Air embolism from routine use", "Pain at the exit site only"], a: 1, r: "Tunneled CVCs have the highest infection rate of all hemodialysis vascular access options (compared to AV fistula which has the lowest). CLABSI prevention includes: strict aseptic technique during access, chlorhexidine exit site care, antibiotic lock solutions, not using the catheter for non-dialysis purposes, and minimizing catheter duration. The hierarchy of preferred access is: AV fistula > AV graft > tunneled CVC > temporary CVC.", s: "Vascular Access" },
  { q: "A patient with IgA nephropathy reports gross hematuria that began 2 days after a sore throat. How does this timing differ from post-streptococcal glomerulonephritis (PSGN)?", o: ["The timing is identical", "IgA nephropathy causes synpharyngitic hematuria (concurrent with or 1-2 days after upper respiratory infection), while PSGN has a latency period of 1-3 weeks after streptococcal infection", "PSGN occurs immediately and IgA has a delay", "Neither is related to infections"], a: 1, r: "The timing of hematuria relative to infection distinguishes these conditions: IgA nephropathy has synpharyngitic hematuria (concurrent with or within 1-2 days of URI, because pre-formed IgA antibodies are immediately deposited), while PSGN has a latent period of 1-3 weeks (time needed to form immune complexes against streptococcal antigens). IgA nephropathy is the most common primary glomerulonephritis worldwide.", s: "Glomerular Disorders" },
  { q: "A dialysis patient develops muscle cramps during the last hour of hemodialysis. What is the most likely cause?", o: ["Electrolyte excess", "Rapid fluid removal (excessive ultrafiltration) causing intravascular volume depletion and muscle ischemia", "Catheter malposition", "Allergic reaction to the dialyzer"], a: 1, r: "Intradialytic muscle cramps are most commonly caused by excessive or rapid fluid removal (ultrafiltration). As fluid is removed too quickly, intravascular volume drops faster than interstitial fluid can refill the vascular space, causing tissue hypoperfusion and muscle cramping. Management: reduce ultrafiltration rate, administer normal saline bolus (100-200 mL), stretch affected muscles. Prevention: avoid excessive interdialytic weight gain, profile UF rates, and use sodium modeling.", s: "Hemodialysis" },
  { q: "A patient with CKD Stage 5 on hemodialysis develops pericarditis with chest pain worsened by inspiration, friction rub on auscultation, and diffuse ST elevation on ECG. What is the treatment?", o: ["NSAIDs as first-line", "Intensified dialysis (daily sessions) to remove uremic toxins causing pericardial inflammation; avoid anticoagulation during dialysis to prevent hemopericardium", "Antibiotics for presumed infection", "No treatment needed"], a: 1, r: "Uremic pericarditis occurs in inadequately dialyzed patients when uremic toxins cause pericardial inflammation. Treatment is intensified dialysis (daily sessions for 1-2 weeks) without heparin anticoagulation (risk of hemorrhagic pericardial effusion/cardiac tamponade). If a pericardial effusion develops with hemodynamic compromise, pericardiocentesis or pericardial window may be needed. NSAIDs should be avoided in ESRD (nephrotoxic and GI bleeding risk).", s: "CKD Complications" },
  { q: "A nurse is educating a patient about how to care for a new AV fistula. Which instruction is correct?", o: ["Keep the arm immobile and below heart level at all times", "Perform hand exercises (squeezing a rubber ball) several times daily to promote fistula maturation by increasing blood flow through the access", "Apply ice to the fistula site daily", "Never touch or feel the fistula"], a: 1, r: "After AV fistula creation, hand exercises (squeezing a ball, using a hand grip exerciser) promote fistula maturation by increasing blood flow velocity through the anastomosis, encouraging venous dilation. Other teaching: no BP, venipuncture, or IV in the fistula arm; avoid tight sleeves and watches on that arm; elevate the arm if swelling occurs initially; assess for thrill and bruit daily; report bleeding, loss of thrill/bruit, numbness, or coldness in the hand.", s: "Vascular Access" },
  { q: "A patient with chronic UTIs has been found to have vesicoureteral reflux (VUR). What is the primary concern?", o: ["Urinary frequency", "Retrograde flow of urine from the bladder into the ureters and kidneys can cause recurrent pyelonephritis and progressive kidney damage (reflux nephropathy)", "Urethral stricture", "Bladder cancer"], a: 1, r: "Vesicoureteral reflux allows infected urine to flow backward from the bladder into the ureters and kidneys, causing recurrent pyelonephritis. Chronic reflux and infection lead to renal scarring (reflux nephropathy), which can progress to CKD and hypertension. Management includes antibiotic prophylaxis, voiding education (timed voiding, double voiding), and surgical correction (ureteral reimplantation or endoscopic injection) for higher-grade reflux.", s: "Urinary Disorders" },
  { q: "A patient on hemodialysis through a fistula reports progressive hand coldness, pain, and numbness distal to the fistula during dialysis. What does the nurse suspect?", o: ["Normal fistula sensation", "Vascular steal syndrome - the fistula is 'stealing' blood from the distal extremity", "Peripheral neuropathy", "Raynaud phenomenon"], a: 1, r: "Vascular steal syndrome occurs when an AV fistula diverts excessive blood flow away from the distal extremity, causing ischemia. Symptoms include: hand pain, coldness, numbness, weakness, and in severe cases, tissue necrosis and gangrene. It is more common with upper arm (brachial artery) fistulas than forearm fistulas. Treatment ranges from observation (mild) to surgical banding, revision, or ligation (severe). Report symptoms immediately.", s: "Vascular Access" },
  { q: "A patient with CKD asks why they need to avoid magnesium-containing antacids (Maalox). The nurse explains:", o: ["There is no concern with magnesium antacids", "The kidneys cannot adequately excrete magnesium in CKD, so magnesium-containing products can cause hypermagnesemia (weakness, hypotension, respiratory depression, cardiac arrest)", "Magnesium interferes with dialysis", "Magnesium antacids worsen proteinuria"], a: 1, r: "In CKD, the kidneys cannot excrete magnesium adequately, making magnesium-containing products (antacids like Maalox, laxatives like milk of magnesia, Epsom salts) dangerous. Hypermagnesemia causes: neuromuscular depression (weakness, loss of DTRs), hypotension, respiratory depression, cardiac conduction abnormalities, and cardiac arrest. Safe antacid alternatives for CKD patients include calcium carbonate (also acts as a phosphate binder) and proton pump inhibitors.", s: "Renal Pharmacology" },
  { q: "A patient with ADPKD presents with sudden severe headache described as 'the worst headache of my life.' The nurse should suspect:", o: ["Tension headache", "Ruptured cerebral aneurysm (subarachnoid hemorrhage) - patients with ADPKD have an increased risk of intracranial aneurysms", "Migraine", "Hypertensive headache"], a: 1, r: "ADPKD is associated with intracranial berry aneurysms (8-12% prevalence vs 2-3% general population). 'Worst headache of my life' with sudden onset (thunderclap headache) is the classic presentation of subarachnoid hemorrhage from a ruptured aneurysm - a neurosurgical emergency. CT head without contrast is the first-line imaging. Screening MRA is recommended for ADPKD patients with family history of aneurysm or subarachnoid hemorrhage.", s: "Genetic Kidney Disease" },
  { q: "A patient's 24-hour urine collection shows creatinine clearance of 8 mL/min. What stage of CKD does this represent, and what does the nurse anticipate?", o: ["CKD Stage 3 - medication adjustment", "CKD Stage 5 (ESRD) - the patient will need renal replacement therapy (dialysis or transplant)", "CKD Stage 1 - no treatment needed", "CKD Stage 4 - monitoring only"], a: 1, r: "GFR/CrCl <15 mL/min defines CKD Stage 5 (end-stage renal disease). At this stage, the kidneys can no longer maintain homeostasis: uremic symptoms develop (nausea, metallic taste, pruritus, fatigue, encephalopathy), fluid and electrolyte imbalances become life-threatening, and renal replacement therapy (hemodialysis, peritoneal dialysis, or kidney transplant) is needed. Absolute indications for dialysis include: refractory hyperkalemia, volume overload, metabolic acidosis, uremic pericarditis, and uremic encephalopathy.", s: "Chronic Kidney Disease" },
  { q: "A patient receiving peritoneal dialysis develops shoulder pain during inflow of dialysate. This is most likely caused by:", o: ["Musculoskeletal injury", "Diaphragmatic irritation from the dialysate - a common complaint that usually resolves with position changes and slower infusion", "Peritonitis", "Catheter perforation"], a: 1, r: "Referred shoulder pain during PD is caused by diaphragmatic irritation from the dialysate fluid. It is a common, generally benign complaint. Management includes: slowing the infusion rate, warming the dialysate to body temperature, reducing fill volume if needed, and repositioning during inflow. The pain typically resolves as the patient adapts to PD. Persistent or severe pain, especially with fever, should raise concern for peritonitis or diaphragmatic leak.", s: "Peritoneal Dialysis" },
  { q: "A patient with CKD is taking calcitriol (active vitamin D). What is the purpose of this medication?", o: ["To replace the vitamin D that the kidneys can no longer activate, promoting calcium absorption and suppressing PTH", "To increase phosphorus absorption", "To treat hypertension", "To improve GFR"], a: 0, r: "In CKD, the kidneys lose the ability to convert 25-hydroxyvitamin D to its active form (1,25-dihydroxyvitamin D or calcitriol) via the 1-alpha-hydroxylase enzyme. Without active vitamin D, intestinal calcium absorption decreases, causing hypocalcemia and triggering secondary hyperparathyroidism. Calcitriol supplementation restores calcium absorption and suppresses PTH secretion. Monitor calcium levels closely - calcitriol can cause hypercalcemia.", s: "Renal Pharmacology" },
  { q: "A patient with renal artery stenosis (RAS) is started on an ACE inhibitor. Two weeks later, creatinine rises from 1.2 to 2.8 mg/dL. What is the most likely explanation?", o: ["Normal ACE inhibitor effect", "In bilateral RAS (or RAS in a solitary kidney), ACE inhibitors remove the compensatory efferent arteriolar constriction that maintains GFR, causing acute kidney injury", "The ACE inhibitor is treating the stenosis", "Unrelated kidney problem"], a: 1, r: "ACE inhibitors dilate the efferent arteriole (which angiotensin II normally constricts to maintain GFR). In bilateral renal artery stenosis, this efferent dilation reduces the intraglomerular pressure that is maintaining GFR in already poorly perfused kidneys, causing a dramatic GFR drop and AKI. ACE inhibitors/ARBs are relatively CONTRAINDICATED in bilateral RAS. A creatinine rise >30% after starting ACEI/ARB should raise suspicion for RAS.", s: "Renal Vascular Disease" },
  { q: "A nurse is assessing a patient with suspected uremic syndrome. Which symptom cluster is most consistent?", o: ["Polydipsia and polyuria", "Uremic frost (crystalline deposits on skin), metallic taste, nausea, asterixis (flapping tremor), pruritus, and pericardial friction rub", "Fever and joint pain", "Chest pain and hemoptysis"], a: 1, r: "Uremic syndrome occurs in advanced CKD/ESRD when waste products (urea, creatinine, and other toxins) accumulate. Manifestations include: GI (nausea, vomiting, anorexia, metallic taste, uremic fetor - ammonia breath), neurological (asterixis, encephalopathy, peripheral neuropathy), dermatological (pruritus, uremic frost - urea crystals on skin), cardiovascular (pericarditis with friction rub, hypertension), hematological (anemia, platelet dysfunction), and musculoskeletal (renal osteodystrophy). These indicate the need for dialysis initiation.", s: "CKD Complications" },
  { q: "A patient on the transplant waiting list asks about living donor kidney transplantation. What should the nurse explain about outcomes?", o: ["Living donor outcomes are worse than deceased donor", "Living donor kidneys have better outcomes than deceased donor kidneys: longer graft survival, shorter waiting time, ability to plan surgery electively, and the option for preemptive transplant before starting dialysis", "There is no difference in outcomes", "Living donation is too dangerous for the donor"], a: 1, r: "Living donor kidney transplant advantages: superior graft survival (median >15-20 years vs 8-12 years for deceased donor), shorter wait time, elective scheduling allowing optimal patient preparation, preemptive transplant option (before dialysis, which improves outcomes), and living donor evaluation ensures a healthy kidney. Living donor risks are real but low: operative mortality ~0.03%, long-term renal function remains adequate with one kidney.", s: "Transplant Nursing" },
  { q: "A patient with acute kidney injury from IV contrast develops oliguria 24 hours after a cardiac catheterization. What nursing action is most important?", o: ["Administer IV furosemide immediately", "Maintain strict intake and output measurement, monitor daily weights, report oliguria to the provider, and monitor potassium and creatinine closely", "Prepare for immediate dialysis", "Restrict all fluids"], a: 1, r: "Post-contrast AKI (contrast-induced nephropathy) typically manifests 24-48 hours after contrast exposure with oliguria and rising creatinine. Nursing priorities: strict I&O and daily weights (fluid balance), monitor labs (potassium, creatinine, BUN), continue IV hydration as ordered, monitor for fluid overload, and report changes promptly. Most cases of CIN are self-limiting and resolve within 7-14 days. Dialysis is rarely needed unless severe.", s: "Acute Kidney Injury" },
  { q: "A patient with ESRD asks why they develop bone pain and are at risk for fractures. The nurse explains this is called:", o: ["Osteoarthritis", "Renal osteodystrophy - bone disease resulting from the mineral and hormonal imbalances in CKD including hyperphosphatemia, hypocalcemia, vitamin D deficiency, and secondary hyperparathyroidism", "Primary osteoporosis", "Paget disease"], a: 1, r: "Renal osteodystrophy (CKD-mineral bone disease) encompasses several bone disorders in CKD: osteitis fibrosa (from hyperparathyroidism - PTH stimulates osteoclasts to resorb bone), osteomalacia (from vitamin D deficiency - impaired bone mineralization), adynamic bone disease (from over-suppression of PTH), and mixed patterns. Prevention and treatment: phosphate binders, active vitamin D, calcimimetics, and maintaining calcium-phosphorus balance.", s: "CKD Complications" },
  { q: "A patient develops tumor lysis syndrome after chemotherapy. Which electrolyte abnormality combination is characteristic?", o: ["Hypokalemia, hypocalcemia, hypophosphatemia", "Hyperkalemia, hyperphosphatemia, hyperuricemia, and hypocalcemia - from massive cell lysis releasing intracellular contents", "Hypernatremia, hypokalemia, alkalosis", "Normal electrolytes with elevated LDH only"], a: 1, r: "Tumor lysis syndrome occurs when rapidly dividing cancer cells are destroyed by chemotherapy, releasing intracellular contents: potassium (hyperkalemia), phosphorus (hyperphosphatemia which binds calcium causing hypocalcemia), uric acid (hyperuricemia which precipitates in renal tubules causing AKI), and nucleic acids. Prevention: aggressive IV hydration, allopurinol or rasburicase (uric acid reduction), and close electrolyte monitoring. TLS can cause fatal cardiac arrhythmias and renal failure.", s: "Renal Emergencies" },
  { q: "A patient on chronic hemodialysis develops restless legs syndrome (RLS). The nurse knows this is related to:", o: ["Excess iron stores", "Uremic toxin accumulation, iron deficiency, and secondary hyperparathyroidism are all implicated in RLS in dialysis patients; optimizing dialysis adequacy and correcting iron deficiency may help", "Excessive exercise", "Antihypertensive medications only"], a: 1, r: "Restless legs syndrome is highly prevalent in dialysis patients (25-50%). Contributing factors include: uremic toxin accumulation (improved with dialysis adequacy), iron deficiency (correct ferritin and TSAT), secondary hyperparathyroidism, peripheral neuropathy, and chronic anemia. Treatment includes: optimizing dialysis, iron supplementation if deficient, gabapentin or pregabalin (preferred over dopamine agonists in CKD), and treating underlying contributing factors.", s: "CKD Complications" },
  { q: "A patient with a kidney transplant 5 years ago develops gradually rising creatinine, proteinuria, and hypertension over several months. What does the nurse suspect?", o: ["Acute rejection", "Chronic rejection (chronic allograft nephropathy) - a gradual process of immune-mediated and non-immune damage to the transplanted kidney", "Urinary tract infection", "Dehydration"], a: 1, r: "Chronic rejection (chronic allograft nephropathy) is the leading cause of late graft failure. It develops over months to years with: gradual creatinine rise, proteinuria, hypertension, and progressive fibrosis on biopsy. Unlike acute rejection (sudden onset, reversible), chronic rejection is generally irreversible and progresses to graft failure despite treatment adjustments. Contributing factors include both immune-mediated damage and non-immune factors (hypertension, diabetes, calcineurin inhibitor toxicity).", s: "Transplant Nursing" },
  { q: "A patient with hyperkalemia has an ECG showing loss of P waves and widened QRS complex. The nurse recognizes this as:", o: ["A benign finding", "An ominous sign of severe hyperkalemia approaching cardiac arrest - emergency treatment with IV calcium is needed immediately", "Normal sinus rhythm", "Atrial fibrillation"], a: 1, r: "ECG progression in hyperkalemia: peaked T waves (early, K+ 5.5-6.5) → PR prolongation → loss of P waves → widened QRS → sine wave pattern → ventricular fibrillation/asystole. Loss of P waves and widened QRS indicates severe hyperkalemia (usually K+ >7-8 mEq/L) with imminent cardiac arrest risk. IV calcium gluconate must be given IMMEDIATELY to stabilize the myocardium. This is a medical emergency.", s: "Electrolyte Management" },
  { q: "A nurse is teaching a patient about the renal diet. Which foods should be limited due to HIGH potassium content?", o: ["White bread and pasta", "Bananas, oranges, potatoes, tomatoes, avocados, and spinach", "Chicken and fish", "White rice and applesauce"], a: 1, r: "High-potassium foods to avoid/limit in CKD: bananas, oranges and orange juice, potatoes (especially baked), tomatoes and tomato sauce, avocados, spinach, beans and lentils, nuts, dairy products, and salt substitutes (contain KCl). Low-potassium alternatives: apples, berries, grapes, pears, white rice, white bread, and cabbage. Cooking methods can reduce potassium: leaching (soaking chopped vegetables in water) removes significant potassium.", s: "Renal Diet" },
  { q: "A patient is diagnosed with minimal change disease after kidney biopsy. The nurse expects treatment to include:", o: ["No treatment needed", "Corticosteroids (prednisone) - minimal change disease is highly responsive to steroid therapy with >90% remission rate in children", "Immediate dialysis", "Surgical intervention"], a: 1, r: "Minimal change disease (MCD) is the most common cause of nephrotic syndrome in children. On light microscopy, glomeruli appear normal; electron microscopy shows podocyte foot process effacement. MCD is highly responsive to corticosteroids: >90% of children and ~80% of adults achieve complete remission with prednisone. Relapses are common and may require steroid-sparing agents (cyclophosphamide, calcineurin inhibitors, rituximab). Prognosis is excellent with preserved renal function in most patients.", s: "Glomerular Disorders" },
  { q: "A patient being prepared for hemodialysis has a new AV fistula. The nurse palpates a thrill. What does this indicate?", o: ["The fistula is clotted and not functioning", "The fistula is patent and functioning - a thrill (palpable vibration from turbulent blood flow) indicates adequate flow through the arteriovenous anastomosis", "The fistula has an infection", "Blood pressure is too high"], a: 1, r: "A thrill is a palpable vibration felt over the AV fistula caused by turbulent blood flow through the arteriovenous anastomosis. A bruit is the audible counterpart heard with a stethoscope. Both indicate fistula PATENCY. Absence of thrill and bruit suggests fistula thrombosis (clotting) and requires immediate evaluation and intervention (thrombectomy, thrombolysis, or angioplasty). Fistula assessment should be performed before every dialysis session.", s: "Vascular Access" },
  { q: "A patient presents with cola-colored urine, periorbital edema, and hypertension 2 weeks after a streptococcal pharyngitis. The nurse suspects:", o: ["Urinary tract infection", "Acute post-streptococcal glomerulonephritis (PSGN) - an immune complex-mediated glomerulonephritis occurring 1-3 weeks after streptococcal infection", "Nephrotic syndrome", "Kidney stone"], a: 1, r: "PSGN is a nephritic syndrome occurring 1-3 weeks after Group A Strep pharyngitis (or 3-6 weeks after skin infection). Immune complexes deposit in glomeruli causing inflammation. Presentation: hematuria (cola/tea-colored urine from RBCs), periorbital/facial edema (worst in morning), hypertension, oliguria, and mild proteinuria. Labs: elevated ASO titer, low C3 complement, RBC casts on urinalysis. Most children recover completely; adults may have residual renal impairment.", s: "Glomerular Disorders" },
  { q: "A diabetic patient on metformin with CKD has a scheduled CT scan with IV contrast. What medication management is required?", o: ["Continue metformin throughout", "Hold metformin before or at the time of contrast administration and for at least 48 hours after, until renal function is confirmed stable", "Double the metformin dose", "Switch to insulin permanently"], a: 1, r: "Metformin is held around contrast procedures in patients with CKD because: if contrast-induced AKI develops, metformin cannot be cleared by the kidneys and accumulates, causing lactic acidosis (a life-threatening complication). Metformin should be held at the time of contrast and for 48 hours after the procedure. It can be resumed after serum creatinine is confirmed to be at baseline. This is especially important with eGFR <45 mL/min.", s: "Renal Pharmacology" },
  { q: "A patient with nephrotic syndrome has severe edema. The provider orders IV albumin followed by furosemide. What is the rationale for this sequence?", o: ["Albumin treats the underlying disease", "Albumin increases intravascular oncotic pressure, pulling fluid from the interstitial space back into the vasculature, making it available for the diuretic (furosemide) to excrete via the kidneys", "The order doesn't matter", "Furosemide should be given first"], a: 1, r: "In nephrotic syndrome, hypoalbuminemia causes decreased oncotic pressure, allowing fluid to leak into interstitial spaces (edema). Diuretics alone may be ineffective because there is insufficient intravascular volume. IV albumin temporarily increases oncotic pressure, drawing edema fluid back into the vascular space. Furosemide given after albumin can then effectively excrete this mobilized fluid. Some protocols co-administer albumin with furosemide (albumin-furosemide drip).", s: "Glomerular Disorders" },
  { q: "A patient on CRRT has a citrate anticoagulation protocol. What electrolyte must be closely monitored?", o: ["Potassium only", "Ionized calcium - citrate chelates calcium, and replacement calcium must be infused to prevent hypocalcemia", "Sodium only", "Magnesium only"], a: 1, r: "Regional citrate anticoagulation works by chelating ionized calcium in the circuit (calcium is essential for the coagulation cascade). This provides anticoagulation within the circuit without systemic anticoagulation. However, some citrate enters the patient's bloodstream and chelates systemic calcium, requiring continuous calcium replacement infusion. Ionized calcium must be monitored frequently (every 4-6 hours or per protocol) to prevent dangerous hypocalcemia (cardiac arrhythmias, seizures).", s: "CRRT" },
  { q: "A patient has a creatinine of 1.0 mg/dL but a BUN of 42 mg/dL (BUN:Creatinine ratio >20:1). What does this elevated ratio suggest?", o: ["Intrinsic renal disease", "Prerenal cause: dehydration, GI bleeding, high protein intake, or catabolic state - conditions that increase urea production or reduce its excretion disproportionately to creatinine", "Normal finding", "Post-renal obstruction"], a: 1, r: "A BUN:Creatinine ratio >20:1 with a normal or mildly elevated creatinine suggests prerenal azotemia or increased urea production. Causes include: dehydration (most common - concentrated urea), GI bleeding (digested blood = protein = urea), high protein diet, catabolic states (burns, sepsis), and corticosteroid use. In intrinsic renal disease, both BUN and creatinine rise proportionately (ratio 10-15:1). This ratio helps distinguish prerenal from intrinsic AKI.", s: "Acute Kidney Injury" },
  { q: "A nurse is educating a PD patient about exit site care. What is the key teaching point?", o: ["Clean the exit site with alcohol daily", "Perform daily exit site care using chlorhexidine or antibacterial soap, assess for redness, drainage, or crusting, and keep the site dry between cleanings to prevent infection", "No care is needed after the initial healing", "Apply hydrogen peroxide to the exit site"], a: 1, r: "PD catheter exit site infection is a major complication leading to peritonitis and catheter loss. Daily exit site care with chlorhexidine or antibacterial soap reduces infection rates. Teach the patient to: wash hands before touching the catheter, clean the exit site daily, assess for infection signs (redness, swelling, drainage, pain, crusting), avoid submersion in water (pools, baths), and secure the catheter to prevent pulling/trauma at the exit site.", s: "Peritoneal Dialysis" },
  { q: "A patient with ESRD develops persistent hiccups, nausea, and a ammonia-like breath odor. These symptoms are caused by:", o: ["Gastroesophageal reflux", "Uremic toxin accumulation causing GI irritation (uremic gastropathy) and the breakdown of urea to ammonia by oral bacteria (uremic fetor)", "Medication side effects only", "Normal aging changes"], a: 1, r: "GI symptoms in ESRD result from uremic toxin accumulation: nausea, vomiting, anorexia, hiccups (diaphragmatic irritation from uremia), metallic taste (dysgeusia), and uremic fetor (ammonia/urine-like breath from urea breakdown by oral bacteria). These symptoms indicate inadequate dialysis or approaching need for dialysis initiation. Improvement occurs with adequate dialysis. Persistent symptoms may indicate need for dialysis dose adjustment.", s: "CKD Complications" },
  { q: "A patient with a kidney stone is prescribed potassium citrate. What is the mechanism of action for stone prevention?", o: ["It dissolves existing stones", "Citrate inhibits calcium stone formation by binding calcium in the urine (reducing free calcium available for crystallization) and by alkalinizing the urine (increasing citrate excretion, which inhibits crystal aggregation)", "It increases uric acid excretion", "It reduces urine volume"], a: 1, r: "Potassium citrate prevents calcium stones through two mechanisms: (1) citrate binds calcium in the urine, reducing free calcium concentration available for crystallization with oxalate or phosphate, and (2) citrate directly inhibits crystal nucleation, growth, and aggregation. Additionally, urine alkalinization from citrate metabolism helps prevent uric acid stones (which form in acidic urine). It also corrects hypocitraturia, a common metabolic risk factor for calcium stone formation.", s: "Urolithiasis" },
  { q: "A dialysis patient's labs show aluminum level of 85 mcg/L (normal <10). What is the likely source and concern?", o: ["Dietary aluminum intake", "Aluminum-containing phosphate binders (aluminum hydroxide) used chronically can cause aluminum toxicity: encephalopathy, osteomalacia, and microcytic anemia", "Water purification failure", "Normal dialysis finding"], a: 1, r: "Chronic use of aluminum-containing phosphate binders (aluminum hydroxide, Alternagel) in CKD patients can cause aluminum accumulation leading to: dialysis dementia/encephalopathy (confusion, speech difficulty, seizures), osteomalacia (aluminum deposits in bone preventing mineralization), and microcytic anemia (aluminum interferes with iron incorporation into hemoglobin). For this reason, aluminum-based binders are now avoided for chronic use. Calcium-based, sevelamer, and lanthanum binders are preferred.", s: "Renal Pharmacology" },
  { q: "A patient with acute tubular necrosis (ATN) from ischemic injury progresses through which phases?", o: ["Only one phase", "Initiation phase (injury), oliguric/maintenance phase (low urine output, rising BUN/Cr), diuretic/recovery phase (increased urine output, risk of dehydration and electrolyte loss), and recovery phase (gradual normalization over months)", "Immediate recovery with no phases", "Chronic phase only"], a: 1, r: "ATN phases: (1) Initiation/onset (hours-days): the injury occurs, creatinine begins to rise. (2) Oliguric/maintenance (1-3 weeks): urine output <400 mL/day, BUN and creatinine rise, hyperkalemia, fluid overload risk - may need dialysis. (3) Diuretic (1-3 weeks): urine output increases dramatically (may exceed 3-5 L/day), risk of dehydration and electrolyte depletion (hypokalemia, hyponatremia). (4) Recovery (months): gradual return of concentrating ability and GFR normalization. Some patients have permanent GFR loss.", s: "Acute Kidney Injury" },
  { q: "A patient with hypokalemia (K+ 2.9 mEq/L) is on IV potassium replacement. What is the maximum safe rate of IV potassium administration through a peripheral line?", o: ["40 mEq/hr through any IV line", "10 mEq/hr through a peripheral IV (higher rates cause phlebitis and require central line with cardiac monitoring)", "No maximum rate exists", "Potassium should only be given orally"], a: 1, r: "IV potassium safety: peripheral IV maximum is 10 mEq/hr at concentrations ≤40 mEq/L (higher concentrations cause phlebitis and burning). Central line allows up to 20-40 mEq/hr with continuous cardiac monitoring (risk of fatal arrhythmia). Never give IV potassium by push (can cause cardiac arrest). Always use an infusion pump. Monitor ECG during rapid replacement. Assess urine output first - potassium is renally excreted, and giving potassium to an oliguric patient risks hyperkalemia.", s: "Electrolyte Management" },
  { q: "A patient with membranous nephropathy has proteinuria of 8 g/day, albumin 2.1 g/dL, and develops acute shortness of breath with pleuritic chest pain. The nurse suspects:", o: ["Pneumonia", "Pulmonary embolism - nephrotic syndrome causes a hypercoagulable state with increased risk of thromboembolic events including renal vein thrombosis and PE", "Asthma exacerbation", "Pericardial effusion"], a: 1, r: "Membranous nephropathy has the highest thromboembolic risk among nephrotic syndromes, especially when albumin <2.5 g/dL. The hypercoagulable state results from urinary loss of antithrombin III, protein C, and protein S. Renal vein thrombosis (flank pain, hematuria, worsening proteinuria) and pulmonary embolism are the most feared complications. Prophylactic anticoagulation may be considered when albumin is severely depressed. This presentation (dyspnea + pleuritic pain + nephrotic syndrome) = PE until proven otherwise.", s: "Glomerular Disorders" },
  { q: "A patient on dialysis is prescribed sevelamer (Renagel) as a phosphate binder. What advantage does sevelamer have over calcium-based binders?", o: ["It is more effective at binding phosphorus", "Sevelamer does not contain calcium, reducing the risk of hypercalcemia and vascular calcification that can occur with calcium-based phosphate binders", "It is less expensive", "It can be taken without meals"], a: 1, r: "Sevelamer (Renagel/Renvela) is a non-calcium, non-aluminum phosphate binder. Advantages over calcium-based binders: no risk of hypercalcemia, reduced vascular calcification (major cause of cardiovascular mortality in dialysis patients), LDL cholesterol reduction (bonus effect). Disadvantages: more pills needed per meal, GI side effects, and higher cost. All phosphate binders must be taken WITH meals to bind dietary phosphorus in the GI tract.", s: "Renal Pharmacology" },
  { q: "A patient recovering from AKI enters the diuretic phase with urine output of 4 liters/day. What is the nursing priority?", o: ["Restrict fluids to prevent fluid overload", "Monitor for dehydration and electrolyte imbalances (hypokalemia, hyponatremia) - replace fluids and electrolytes as ordered to match the high output", "This level of output is concerning and dialysis should continue", "No monitoring is needed during recovery"], a: 1, r: "During the diuretic phase of ATN recovery, urine output can be massive (3-5+ L/day) because recovering tubules cannot yet concentrate urine. This creates risk for: dehydration (match IV fluids to output), hypokalemia (potassium lost in dilute urine), hyponatremia, and volume depletion. Careful I&O monitoring, daily weights, and frequent electrolyte checks are essential. This phase typically lasts 1-3 weeks before concentrating ability returns.", s: "Acute Kidney Injury" },
  { q: "A patient with IgA nephropathy is started on an ACE inhibitor despite having a normal blood pressure. The nurse understands this is prescribed for:", o: ["Hypertension treatment", "Proteinuria reduction and renoprotection - ACE inhibitors reduce intraglomerular pressure and proteinuria independent of systemic blood pressure effects", "Cardiac protection only", "There is no indication for this"], a: 1, r: "ACE inhibitors/ARBs are prescribed in proteinuric kidney diseases (including IgA nephropathy) specifically for their renoprotective antiproteinuric effect, even in normotensive patients. By dilating the efferent arteriole, they reduce intraglomerular pressure, which decreases protein filtration and reduces the direct toxic effects of proteinuria on tubular cells. Reducing proteinuria to <1 g/day significantly slows CKD progression. This effect is independent of blood pressure reduction.", s: "Glomerular Disorders" },
  { q: "A nurse is caring for a patient with syndrome of inappropriate ADH secretion (SIADH). Which finding is expected?", o: ["Polyuria and hypernatremia", "Dilutional hyponatremia with concentrated urine (urine osmolality > serum osmolality), euvolemia (no edema), and decreased serum osmolality", "Dehydration with elevated BUN", "Hyperkalemia"], a: 1, r: "SIADH causes excessive water retention from inappropriate ADH secretion. Key findings: dilutional hyponatremia (serum Na <135), low serum osmolality (<280), concentrated urine (osmolality >100, often >300), high urine sodium (>40), and clinical euvolemia (no edema or dehydration because the excess water distributes throughout body compartments). Treatment: fluid restriction (primary), hypertonic saline for severe/symptomatic hyponatremia, demeclocycline or vaptans for chronic SIADH.", s: "Electrolyte Management" }
];
